head.script:
//==================================================================================================================
// id       : zz_670_05_01b
// 이름     : 사용자별 권한 이력
// 경로     : 공통/시스템관리/권한/
// 작 성 자 : 오영재
// 작 업 일 : 2026-1-6
// 사용계정 : 내부
// 비고     :
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//==================================================================================================================
scwin.empNo = $c.gus.cfIsNull($c.data.getMemInfo("userId")) ? '' : $c.data.getMemInfo("userId");

scwin.today = $c.date.getServerDateTime("yyyyMMdd");

scwin.vCurDate = scwin.today; // 서버를 기준으로 현재 날짜 반환
let lastDay = scwin.today.substring(0, 4) + scwin.today.substring(4, 6) + new Date(scwin.today.substring(0, 4), scwin.today.substring(4, 6), 0).getDate(); // 마지막날
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01"; // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = lastDay; // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)

scwin.onpageload = function () {

};

scwin.onUdcCompleted = function () {
    ed_searchStDt.setValue(scwin.vQryStDt);
    ed_searchEndDt.setValue(scwin.vQryEndDt);
}

//-------------------------------------------
// 조회
//-------------------------------------------	
scwin.f_retrieve = async function () {

    let ret;
    ret = await $c.gus.cfValidate([ed_searchStDt, ed_searchEndDt, ed_userId]);
    if (!ret) {
        return;
    }

    //날짜 입력 오류 검사 관련 부분
    if (ed_searchStDt.getValue() != "" && ed_searchEndDt.getValue() != "") {
        if (!$c.gus.cfIsAfterDate(ed_searchStDt.getValue(), ed_searchEndDt.getValue())) {
            $c.gus.cfAlertMsg("조회종료일자는 시작일자보다 이후로 입력하세요");
            //PAGE_MOVE_CONFIRM = false;
            return;
        }
    }

    // 조회TR
    //tr_retrieve.post();	    
    dma_search.set("userId", ed_userId.getValue());
    $c.sbm.execute(sbm_retrieve);
}

scwin.sbm_retrieve_submitdone = function (e) {
    let rowCnt = ds_userPriv.getRowCount();
    if (rowCnt == 0) {
        $c.gus.cfAlertMsg("조회결과가 존재하지 않습니다.");
        return;
    } else {
        //cfShowTotalRows(totalRows, rowCnt);// 총 조회건수 표시
        ed_totalRows.setValue(rowCnt);
    }
}
scwin.sbm_retrieve_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
}

scwin.sbm_save_submitdone =async function (e) {
    await $c.gus.cfAlertMsg("권한복구가 완료되었습니다.");
    scwin.f_retrieve();
}
scwin.sbm_save_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
}

scwin.sbm_userPrivYn_submitdone = function (e) {
    let rowCnt = ds_userPrivYn.getRowCount();
    if (rowCnt == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return;
    } else {
        if (ds_userPrivYn.getCellData(0, "col1") == "0") {
            scwin.f_UserHistYn();
        } else {
            $c.win.alert("현재 사용자 권한이 등록되어있습니다.");
            return;
        }
    }
}
scwin.sbm_userPrivYn_submiterror = function (e) { }

//-------------------------------------------------------------------------
// 퇴사일자 기준 권한 복구
//-------------------------------------------------------------------------
scwin.f_save = async function () {

    if (ds_userPriv.getRowCount() == 0) {
        await $c.win.alert("조회된 내역이 없습니다.");
    }

    if (ed_userBlockDt.getValue() == "") {
        await $c.win.alert("적용일자를 입력하세요");
    }

    let ret;
    ret = await $c.gus.cfValidate([ed_userId]);
    if (!ret) return;

    scwin.f_getUserPrivYn();

}

// 사용자 현재 권한 여부 확인
scwin.f_getUserPrivYn = function () {
    // SELECT 절 
    let param1 =
        "COUNT(*)  		as COL1 "
        + ",''			 	as COL2 "
        + ",''			 	as COL3 "
        + ",''			 	as COL4 "
        + ",''  			as COL5 "
        + ",'' 				as COL6 "
        + ",'' 				as COL7 "
        + ",'' 				as COL8 "
        + ",'' 				as COL9 "
        + ",'' 				as COL10 "
        ;

    // 대상테이블 	
    let param2 = "TB_ZZ412";
    let param3 = "AND USER_ID = '" + ed_userId.getValue() + "'";
    let param4 = "1";

    dma_query.set("sysCd", "CommonEBC");
    dma_query.set("queryId", "dinymicQueryTest");
    dma_query.set("param1", param1);
    dma_query.set("param2", param2);
    dma_query.set("param3", param3);
    dma_query.set("param4", param4);
    $c.sbm.execute(sbm_userPrivYn);
    /*
    ds_userPrivYn.DataId = 
        "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 
                                                                                    + "&param2=" + param2 
                                                                                    + "&param3=" + param3
                                                                                    + "&param4=" + param4;
    ds_userPrivYn.Reset(); 
    */
}

scwin.f_UserHistYn = function () {
    // SELECT 절 
    let param1 =
        "COUNT(*)  		as COL1 "
        + ",''			 	as COL2 "
        + ",''			 	as COL3 "
        + ",''			 	as COL4 "
        + ",''  			as COL5 "
        + ",'' 				as COL6 "
        + ",'' 				as COL7 "
        + ",'' 				as COL8 "
        + ",'' 				as COL9 "
        + ",'' 				as COL10 "
        ;

    // 대상테이블 	
    let param2 = "TB_ZZ412_LOG";
    let param3 = "AND USER_ID = '" + ed_userId.getValue() + "'"
        + "AND TO_CHAR(CREATE_DTM,'YYYYMMDD') =  '" + ed_userBlockDt.getValue() + "'";
    let param4 = "1";

    dma_query.set("sysCd", "CommonEBC");
    dma_query.set("queryId", "dinymicQueryTest");
    dma_query.set("param1", param1);
    dma_query.set("param2", param2);
    dma_query.set("param3", param3);
    dma_query.set("param4", param4);
    $c.sbm.execute(sbm_userHistYn);

    /*
    ds_userHistYn.DataId = 
        "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 
                                                                                    + "&param2=" + param2 
                                                                                    + "&param3=" + param3
                                                                                    + "&param4=" + param4;
    ds_userHistYn.Reset(); 
    */
}

//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (flag, check) {

    switch (flag) {
        case '1':
            // 사원
            let param = '';

            udc_userId.setSelectId("retrieveAcEmpInfo");
            udc_userId.cfCommonPopUp(
                scwin.udc_userId_cb, 
                ed_userId.getValue().trim(), 
                ed_userNm.getValue(), 
                check, 
                null, 
                null, 
                null, 
                null, 
                param, 
                null, 
                null, 
                null, 
                null,
                null,
                'F'
                );

            break;
        default:
            break;
    }
}

scwin.udc_userId_cb = function (rtnList) {
    scwin.f_resultPopEd(ed_userId, ed_userNm, rtnList);
}

//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function (strCd, strNm, rtnList) {

    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        strCd.setValue(rtnList[0]);	// 코드
        strNm.setValue(rtnList[1]);	// 명
        strCd.options.hidVal = rtnList[0];  // 히든값
    } else {
        strCd.setValue("");
        strNm.setValue("");
        strCd.options.hidVal = "";
    }
}

scwin.btn_save_onclick = function (e) {
    scwin.f_save();
};

scwin.udc_userId_onclickEvent = function (e) {
    scwin.f_openPopUp('1', 'F')
};

scwin.udc_userId_onblurCodeEvent = function (e) {
    if (ed_userId.getValue().trim().length != 0) {
        scwin.f_openPopUp('1', 'F');
    } else {
        ed_userId.setValue("");
        ed_userNm.setValue("");
    }
};

scwin.btn_search_onclick = function (e) {
    scwin.f_retrieve();
};

scwin.sbm_userHistYn_submitdone = async function (e) {
    if( ds_userHistYn.getRowCount() == 0 ){
		$c.gus.cfAlertMsg(MSG_CM_ERR_003);
		return;
	} else {
		await $c.win.alert(ds_userHistYn.getCellData(0,"col1"));
		if(ds_userHistYn.getCellData(0,"col1")!="0"){
                if( await $c.win.confirm("저장하시겠습니까?") ){
                    dma_search.set("userId", ed_userId.getValue());
                    $c.sbm.execute(sbm_save);
	   		    	//tr_save.post();
                }
		}else{
 	   		$c.win.alert("적용일자 기준 권한이력이 없습니다.");
  	   		return;
 		}
	}
};
